def process_string(s, index=0, root=None):
    if index >= len(s):
        return root
    char = s[index].lower()
    if root is None or char not in [node.value for node in get_all_nodes(root)]:
        root = insert(root, char)
    return process_string(s, index + 1, root)

def get_all_nodes(root):
    nodes = []
    def traverse(node):
        if node:
            nodes.append(node)
            traverse(node.left)
            traverse(node.right)
    traverse(root)
    return nodes

